// OrdersActionsLimitTVPost Тело запроса на создание новой лимитной заявки
type OrdersActionsLimitTVPost struct {
	// AllowMargin Флаг, подтверждающий согласие клиента с начальным уровнем риска (КНУР) на выставление заявки с потенциальной непокрытой позицией.
	//
	// Должен быть `true`:
	// * При любом выставлении или изменении биржевых заявок на срочном рынке, в том числе для закрытия ранее открытых позиций
	// * При выставлении или изменении биржевых заявок на фондовом и валютном рынках, если в результате откроется новая непокрытая позиция или увеличится минус по существующей
	// * При выставлении или изменении условных заявок независимо от выбранного рынка
	//
	// Может быть `false` или не указан в запросе, если:
	// * Клиенту присвоен другой уровень риска
	// * Подключена услуга 100% обеспечения
	AllowMargin *FlagAllowMargin `json:"allowMargin,omitempty"`

	// Comment Пользовательский комментарий к заявке. Максимальная длина комментария — 100 символов
	Comment *FieldCustomComment `json:"comment,omitempty"`

	// IcebergFixed Видимая постоянная часть айсберг-заявки в лотах. Указывается при создании заявки, может быть впоследствии изменена только в заявках на фондовом и валютном рынках
	IcebergFixed *FieldQuantityFixed `json:"icebergFixed,omitempty"`

	// IcebergVariance Амплитуда отклонения (в % от постоянной части) случайной надбавки к видимой части айсберг-заявки, указанная при создании лимитной заявки. Только срочный рынок
	IcebergVariance *FieldQuantityVariance `json:"icebergVariance,omitempty"`

	// Instrument Информация об инструменте и бирже
	Instrument *ObjectInstrumentFieldsSymbolExchangeGroup `json:"instrument,omitempty"`

	// Price Цена
	Price *FieldPriceCommon `json:"price,omitempty"`

	// Quantity Количество (лоты)
	Quantity *FieldQuantityBatchCommon `json:"quantity,omitempty"`

	// Side Направление сделки:
	//   * `buy` — Купля
	//   * `sell` — Продажа
	Side *FieldSideCommon `json:"side,omitempty"`

	// TimeInForce Условие выставления заявки с учётом возможности её исполнения:
	//   * `oneday` — Исполнение в течение одного торгового дня. При истечении этого срока неисполненный остаток снимается
	//   * `immediateorcancel` — Исполнение немедленно на весь доступный объём встречных заявок. Неисполненный остаток отменяется
	//   * `fillorkill` — Исполнение немедленно на весь указанный объём без остатка. Если исполнение без остатка невозможно — заявка отменяется
	//   * `attheclose` — Исполнение в момент закрытия торгов по достигнутой на тот момент рыночной цене. Только для SPBX (на MOEX автоматически меняется на `fillorkill`) и только для рыночных заявок, т.к. цена лота зависит от рыночной цены на момент исполнения
	//   * `goodtillcancelled` — Исполнение в течение максимально доступного периода на бирже. Например, в течение года для MOEX. Только для срочного рынка
	//   * `bookorcancel` — [Пассивная заявка](https://www.moex.com/s3424). Выставляется на биржу только если её цена или величина спреда хуже аналогичных показателей встречных заявок
	TimeInForce *FieldExecutionPeriod `json:"timeInForce,omitempty"`

	// User Информация о пользователе
	User *ObjectUserPortfolioOnly `json:"user,omitempty"`
}

